require"UI.UIBase"require"UI.UIBlock"require"UI.UI_BlockEmo"UI_DesktopChat=UIBase:Inherit()function UI_DesktopChat:OnCreate()UI_DesktopChat.Inst=self;self:Init()end;function UI_DesktopChat:Init()self.block_emo=UI_BlockEmo:Init(self.transform:Find('container_chat'):Find('container_chat_choose'))self.nstip=self.block_emo.transform.parent:Find("btn_expand"):Find('nstip')self.nstip2=self.block_emo.transform:Find('nstip')end;function UI_DesktopChat:GetBlockEmo()return self.block_emo end;function UI_DesktopChat:ShowEmo(a)self.block_emo.transform.parent.gameObject:SetActive(a or false)end;function UI_DesktopChat:ShowNstip(a)if self.nstip then self.nstip.gameObject:SetActive(a or false)end;if self.nstip2 then self.nstip2.gameObject:SetActive(a or false)end end;function UI_DesktopChat:Show()self.transform.gameObject:SetActive(true)end;function UI_DesktopChat:Hide()self.transform.gameObject:SetActive(false)end;return UI_DesktopChat